      ]
    },
    {
      "name": "Modify",
      "description": "Méthodes qui transforment ou enrichissent des objets existants.",
      "subcategories": [
        { "name": "update", "examples": ["update_record", "edit_text", "patch_code"] },
        { "name": "merge", "examples": ["merge_branches", "combine_data"] },
