      "description": "Méthodes qui déclenchent, exécutent ou communiquent avec l'extérieur.",
      "subcategories": [
        { "name": "connect", "examples": ["connect_api", "open_socket"] },
        { "name": "query", "examples": ["query_database", "search_index"] },
        { "name": "prompt", "examples": ["prompt_agent", "ask_question"] },
        { "name": "execute", "examples": ["execute_task", "run_cron", "launch_scenario"] },
